import { useEffect, useState } from 'react';
import axios from 'axios';
import { getStoredUser, setStoredUser } from '../utils/auth';
import { buildApiUrl } from '../utils/api';

const ADMIN_ACCOUNT_URL = buildApiUrl('/admin/account');

function AdminAccountManager() {
  const storedUser = getStoredUser();
  const [currentAdminEmail, setCurrentAdminEmail] = useState(storedUser?.email || '');
  const [username, setUsername] = useState(storedUser?.username || '');
  const [phone, setPhone] = useState(storedUser?.phone || '');
  const [newEmail, setNewEmail] = useState(storedUser?.email || '');
  const [currentPassword, setCurrentPassword] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [loadingCurrentAdmin, setLoadingCurrentAdmin] = useState(true);
  const [success, setSuccess] = useState('');
  const [error, setError] = useState('');

  useEffect(() => {
    async function loadAdminAccount() {
      try {
        const response = await axios.get(ADMIN_ACCOUNT_URL, {
          withCredentials: true,
        });

        const adminUser = response.data.user;
        setCurrentAdminEmail(response.data.admin_email || adminUser?.email || '');
        setUsername(adminUser?.username || '');
        setPhone(adminUser?.phone || '');
        setNewEmail(response.data.admin_email || adminUser?.email || '');
      } catch (requestError) {
        setError(requestError.response?.data?.message || 'Unable to load the current admin account.');
      } finally {
        setLoadingCurrentAdmin(false);
      }
    }

    loadAdminAccount();
  }, []);

  async function handleSubmit(event) {
    event.preventDefault();
    setError('');
    setSuccess('');

    setLoading(true);

    try {
      const formData = new FormData();
      formData.append('username', username);
      formData.append('phone', phone);
      formData.append('new_email', newEmail);
      formData.append('current_password', currentPassword);
      formData.append('new_password', newPassword);

      const response = await axios.post(ADMIN_ACCOUNT_URL, formData, {
        withCredentials: true,
      });

      setStoredUser(response.data.user);
      setCurrentAdminEmail(response.data.admin_email || response.data.user?.email || '');
      setNewEmail(response.data.admin_email || response.data.user?.email || '');
      setUsername(response.data.user?.username || '');
      setPhone(response.data.user?.phone || '');
      setCurrentPassword('');
      setNewPassword('');
      setSuccess(response.data.message);
    } catch (requestError) {
      const message = requestError.response?.data?.message || 'Unable to update the admin account.';

      setError(message);
    } finally {
      setLoading(false);
    }
  }

  return (
    <section className="card shadow p-4 h-100">
      <div className="mb-3">
        <h3 className="text-primary mb-1">Admin Security</h3>
        <p className="text-muted mb-0">
          Change the active admin email and set a new password for future sign-ins.
        </p>
      </div>

      {loadingCurrentAdmin && <p className="text-muted mb-3">Loading admin account...</p>}
      {!loadingCurrentAdmin && (
        <p className="small text-muted mb-3">
          Current admin email: <strong>{currentAdminEmail || 'Not set'}</strong>
        </p>
      )}

      {success && <div className="alert alert-success">{success}</div>}
      {error && <div className="alert alert-danger">{error}</div>}

      <form onSubmit={handleSubmit}>
        <div className="mb-3">
          <label className="form-label">Admin Username</label>
          <input
            type="text"
            className="form-control"
            value={username}
            onChange={(event) => setUsername(event.target.value)}
            placeholder="Enter the admin username"
            required
          />
        </div>

        <div className="mb-3">
          <label className="form-label">Admin Phone</label>
          <input
            type="tel"
            className="form-control"
            value={phone}
            onChange={(event) => setPhone(event.target.value)}
            placeholder="Enter the admin phone number"
          />
        </div>

        <div className="mb-3">
          <label className="form-label">New Admin Email</label>
          <input
            type="email"
            className="form-control"
            value={newEmail}
            onChange={(event) => setNewEmail(event.target.value)}
            placeholder="Enter the new admin email"
            required
          />
        </div>

        <div className="mb-3">
          <label className="form-label">Current Admin Password</label>
          <input
            type="password"
            className="form-control"
            value={currentPassword}
            onChange={(event) => setCurrentPassword(event.target.value)}
            placeholder="Enter the current admin password"
            autoComplete="current-password"
            required
          />
        </div>

        <div className="mb-3">
          <label className="form-label">New Admin Password</label>
          <input
            type="password"
            className="form-control"
            value={newPassword}
            onChange={(event) => setNewPassword(event.target.value)}
            placeholder="Enter the new admin password"
            autoComplete="new-password"
            minLength={8}
            required
          />
          <small className="text-muted">Use at least 8 characters with letters and numbers.</small>
        </div>

        <button type="submit" className="btn btn-primary" disabled={loading}>
          {loading ? 'Updating Admin...' : 'Update Admin Account'}
        </button>
      </form>
    </section>
  );
}

export default AdminAccountManager;
